COMPACT_RUNTIME_PROMPT_KEYS = frozenset({
    "character_prompt_template",
    "world_prompt_template",
    "common_style_guide",
    "meta_instruction",
    "meta_instruction_sfw",
    "player_prompt",
    "summary_prompt",
    "sfw_content_restriction",
    "scene_analyzer_prompt",
    "scene_analyzer_prompt_sfw",
})


def _is_blank_compact_runtime_prompt(key: str, content: Optional[str]) -> bool:
    return key in COMPACT_RUNTIME_PROMPT_KEYS and isinstance(content, str) and not content.strip()


async def _use_default_for_blank_runtime_prompt(key: str, source: str, cache=None) -> str:
    content = DEFAULT_PROMPTS[key]
    _prompt_cache[key] = content
    logger.warning("Prompt '%s' from %s is blank; using compact default", key, source)
    if cache:
        await cache.set_prompt(key, content)
    return content


async def init_prompt_cache(db: AsyncSession):
    global _prompt_cache, _prompt_cache_initialized

    try:
        result = await db.execute(select(Prompt))
        prompts = result.scalars().all()

        _prompt_cache = {}
        for p in prompts:
            content = p.content
            if _is_blank_compact_runtime_prompt(p.key, content):
                logger.warning(
                    "Prompt '%s' from database is blank during cache init; using compact default",
                    p.key,
                )
                content = DEFAULT_PROMPTS[p.key]
            _prompt_cache[p.key] = content

        cache = get_cache()
        if cache:
            for key, content in _prompt_cache.items():
                await cache.set_prompt(key, content)
            logger.info(f"Loaded {len(prompts)} prompts into Redis cache")

        _prompt_cache_initialized = True
        logger.info(f"Loaded {len(_prompt_cache)} prompts from database into cache")
    except Exception as e:
        logger.warning(f"Failed to load prompts from database: {e}. Using defaults.")
        _prompt_cache = {}
        _prompt_cache_initialized = True

async def get_prompt(key: str) -> str:
    cache = get_cache()
    if cache:
        cached = await cache.get_prompt(key)
        if cached:
            if _is_blank_compact_runtime_prompt(key, cached):
                return await _use_default_for_blank_runtime_prompt(key, "Redis", cache)
            return cached

    if key in _prompt_cache:
        content = _prompt_cache[key]
        if _is_blank_compact_runtime_prompt(key, content):
            return await _use_default_for_blank_runtime_prompt(key, "database cache", cache)
        if cache:
            await cache.set_prompt(key, content)
        return content

    if key in DEFAULT_PROMPTS:
        logger.warning(f"Prompt '{key}' not found in cache, using default")
        content = DEFAULT_PROMPTS[key]
        if cache:
            await cache.set_prompt(key, content)
        return content

    logger.error(f"Prompt '{key}' not found in cache or defaults!")
    raise KeyError(f"Prompt '{key}' not found")

async def clear_cache():
    global _prompt_cache
    _prompt_cache = {}

    cache = get_cache()
    if cache:
        await cache.invalidate_all_prompts()

    logger.info("Prompt cache cleared")

async def reload_cache(key: str, content: str):
    global _prompt_cache
    if _is_blank_compact_runtime_prompt(key, content):
        logger.warning("Blank compact runtime prompt '%s' rejected during cache reload; using default", key)
        content = DEFAULT_PROMPTS[key]

    _prompt_cache[key] = content

    cache = get_cache()
    if cache:
        await cache.set_prompt(key, content)

    logger.info(f"Prompt '{key}' updated in cache")


def get_default_modifier(name: str, stage: int, is_nsfw: bool, gender: str = "female") -> str:
    """Дефолтные модификаторы в зависимости от стадии и типа"""
    if gender == "male":
        openness = "открыт"
        in_love = "влюблён"
        attached = "привязан"
    else:
        openness = "открыта"
        in_love = "влюблена"
        attached = "привязана"

    if is_nsfw:
        defaults = {
            1: f"{name} ведёт себя сдержанно, с осторожностью.|разговор, лёгкий флирт",
            2: f"{name} более {openness}, проявляет интерес.|разговор, флирт, прикосновения",
            3: f"{name} доверяет, показывает привязанность.|всё из stage_2, объятия, поцелуи",
            4: f"{name} полностью {openness} и {in_love}.|без ограничений",
        }
    else:
        defaults = {
            1: f"{name} ведёт себя сдержанно, соблюдает дистанцию.|вежливый разговор",
            2: f"{name} становится дружелюбнее, проявляет интерес.|дружеский разговор, улыбки",
            3: f"{name} доверяет и показывает привязанность.|всё из stage_2, объятия",
            4: f"{name} полностью {openness}, глубоко {attached}.|глубокая близость",
        }
    return defaults[stage]


async def create_or_update_character_modifiers(
    character_id: str,
    character_name: str,
    is_nsfw: bool,
    modifiers: dict,
    db: AsyncSession,
    gender: str = "female",
):
    """Создать или обновить модификаторы стадий для персонажа"""
    for stage_num in range(1, 5):
        prompt_key = f"character_modifiers_{character_id}_stage_{stage_num}"
        value = modifiers.get(stage_num) or get_default_modifier(character_name, stage_num, is_nsfw, gender)

        result = await db.execute(select(Prompt).where(Prompt.key == prompt_key))
        prompt = result.scalar_one_or_none()

        if prompt:
            prompt.content = value
            prompt.name = f"Модификатор стадии {stage_num} для {character_name}"
        else:
            prompt = Prompt(
                key=prompt_key,
                category="character_modifiers",
                name=f"Модификатор стадии {stage_num} для {character_name}",
                content=value
            )
            db.add(prompt)

        await reload_cache(prompt_key, value)

    logger.info(f"Character modifiers for '{character_id}' created/updated")


async def get_character_modifiers_from_db(character_id: str, db: AsyncSession) -> dict:
    """Получить модификаторы для персонажа из БД"""
    modifiers = {}
    for stage_num in range(1, 5):
        prompt_key = f"character_modifiers_{character_id}_stage_{stage_num}"
        result = await db.execute(select(Prompt).where(Prompt.key == prompt_key))
        prompt = result.scalar_one_or_none()
        modifiers[stage_num] = prompt.content if prompt else ""
    return modifiers
